const str = JSON.stringify(items[0].binary?.data || items[0].json);
let hash = 0;
for (let i = 0; i < str.length; i++) {
  hash = ((hash << 5) - hash) + str.charCodeAt(i);
  hash |= 0;
}
return items.map(i => {
  i.json.capture_hash = Math.abs(hash).toString(16);
  return i;
});

// Upstage Document Parse 실제 응답: { content: { markdown, html }, elements: [...] }
const content = $json.content || {};
const parsed_markdown = content.markdown || content.html || '';
const layout_blocks   = $json.elements || [];
// parse_confidence: Upstage API 응답에 confidence 필드 없음 → 마크다운 길이 기반 대체
const parse_confidence = (parsed_markdown.length > 100) ? 1.0
  : (parsed_markdown.length > 20) ? 0.6 : 0.2;
return [{ json: { ...$json, parsed_markdown, layout_blocks, parse_confidence }, binary: $binary }];

// Upstage IE 실제 응답: { extracted_fields: { field: { value, confidence, evidence_text } } }
const ef = $json.extracted_fields || {};

// 모든 evidence_text 중 가장 긴 것을 대표 근거로 사용
const allEvidence = Object.values(ef)
  .map(f => f?.evidence_text || '')
  .filter(Boolean)
  .sort((a, b) => b.length - a.length);

// 전체 confidence 평균
const confidences = Object.values(ef).map(f => f?.confidence ?? 1).filter(v => v > 0);
const extract_confidence = confidences.length
  ? confidences.reduce((s, v) => s + v, 0) / confidences.length : 0;

return [{ json: {
  ...$json,
  deadline:        ef.deadline?.value        || ef.event_date?.value  || null,
  amount:          ef.amount?.value          || ef.price?.value       || null,
  title:           ef.title?.value           || $json.title           || null,
  required_submission: ef.required_submission?.value
    ? (Array.isArray(ef.required_submission.value)
        ? ef.required_submission.value
        : [ef.required_submission.value])
    : [],
  evidence_text:   allEvidence[0]            || null,
  extract_confidence,
}, binary: $binary }];

const raw_query = items[0].json.raw_query 
  || items[0].json.body?.raw_query
  || $('Validate_Query').first().json.raw_query
  || $('Validate_Query').first().json.body?.raw_query
  || '';

const binaryKey = Object.keys(items[0].binary || {})[0];
const binaryData = items[0].binary[binaryKey];
const text = Buffer.from(binaryData.data, 'base64').toString('utf-8');
const records = JSON.parse(text.replace(/^\uFEFF/, ''));

if (!Array.isArray(records)) throw new Error('records가 배열이 아닙니다');

return [{ json: { raw_query, all_records: records } }];

