// Solar는 choices[0].message.content에 JSON 문자열을 반환
const raw = $json?.choices?.[0]?.message?.content;
if (!raw) {
  return [{ json: { ...$json, error: 'Solar_Query_Planner: empty response', query_intent: null } }];
}
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  return [{ json: { ...$json, error: 'Solar_Query_Planner: JSON parse failed: ' + e.message, query_intent: null } }];
}
// 파싱 결과를 query_plan + 최상위 필드 모두 노출
return [{ json: { ...$json, query_plan: parsed, ...parsed } }];

const queryPlan = $json.query_plan || $json;
const filters = queryPlan.filters || {};
const sortBy = queryPlan.sort_by || 'deadline';
const limit = queryPlan.limit || 5;

const rawRecords = $json.all_records || [];

const allRecords = rawRecords.map(r => {
  const meta = r.metadata || {};
  const ev = r.evidence_text || {};
  const evidenceStr = Object.values(ev).filter(Boolean).join(' ');
  return {
    capture_id:    r.image_id,
    file_name:     r.file_name,
    doc_type:      meta.doc_type,
    title:         meta.title,
    deadline:      meta.deadline,
    amount:        meta.amount,
    evidence_text: evidenceStr,
    evidence_obj:  ev,
    source:        meta.source,
    location_name: meta.location_name,
    confidence:    meta.confidence,
    needs_review:  meta.confidence < 0.8,
  };
}).filter(r => r.evidence_text && r.doc_type !== 'noise');

const filtered = allRecords.filter(r => {
  if (filters.doc_type && r.doc_type !== filters.doc_type) return false;
  if (filters.date_range?.start || filters.date_range?.end) {
    const deadline = r.deadline ? new Date(r.deadline) : null;
    if (!deadline) return false;
    if (filters.date_range.start && deadline < new Date(filters.date_range.start)) return false;
    if (filters.date_range.end   && deadline > new Date(filters.date_range.end))   return false;
  }
  if (filters.keywords?.length) {
    const text = [r.evidence_text, r.title, r.doc_type, r.source].join(' ').toLowerCase();
    return filters.keywords.some(k => text.includes(k.toLowerCase()));
  }
  return true;
});

filtered.sort((a, b) => {
  if (sortBy === 'deadline') return (a.deadline || '9999') < (b.deadline || '9999') ? -1 : 1;
  if (sortBy === 'amount')   return (Number(b.amount) || 0) - (Number(a.amount) || 0);
  return 0;
});

return [{ json: { ...$json, candidate_results: filtered.slice(0, limit) } }];

